// Supabase REST returns an array. Turn it into one item per lead.
const res = $input.first().json;
const arr = Array.isArray(res) ? res : (Array.isArray(res.body) ? res.body : []);
return arr.map(r => ({ json: r }));

// Normalise the URL and carry id/name forward.
const lead = $input.item.json;
let url = (lead.website || '').trim();
if (url && !/^https?:\/\//i.test(url)) url = 'https://' + url;
return { json: { id: lead.id, website: url, name: lead.name || null } };

// Lightweight technical checks parsed from the homepage HTML.
const resp = $('Fetch HTML').item.json;
const lead = $('Prep').item.json;
const html = (resp && resp.body) ? String(resp.body) : '';
const status = resp ? resp.statusCode : null;
const reachable = status != null && status >= 200 && status < 400;
const isHttps = /^https:\/\//i.test(lead.website || '');

const lower = html.toLowerCase();
const hasViewport = /<meta[^>]+name=["']viewport["']/i.test(html);
const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : '';
const descMatch = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']*)["']/i);
const metaDescription = descMatch ? descMatch[1].trim() : '';

const hasTel = /href=["']tel:/i.test(html);
const hasMailto = /href=["']mailto:/i.test(html);
const hasForm = /<form/i.test(html);
const hasBooking = /(calendly|acuity|cal\.com|booking|appointment|schedule a)/i.test(lower);
const contactMethods = [hasTel && 'phone', hasMailto && 'email', hasForm && 'form', hasBooking && 'booking'].filter(Boolean);

const widgets = ['intercom','drift','tawk','crisp','hubspot','zendesk','livechat','tidio','freshchat','manychat'];
const chatWidget = widgets.find(w => lower.includes(w)) || null;

const years = (html.match(/(?:\u00a9|&copy;|copyright)[^0-9]{0,12}(20\d{2})/gi) || [])
  .map(m => parseInt((m.match(/20\d{2}/) || [])[0])).filter(Boolean);
const latestYear = years.length ? Math.max(...years) : null;
const currentYear = new Date().getFullYear();
const staleCopyright = latestYear != null ? (currentYear - latestYear >= 2) : null;

const tech = {
  reachable, statusCode: status, isHttps, hasViewport,
  title, titleLength: title.length,
  metaDescription, metaDescriptionLength: metaDescription.length,
  contactMethods, hasContactMethod: contactMethods.length > 0,
  chatWidget, hasChatWidget: !!chatWidget,
  copyrightYear: latestYear, staleCopyright
};
return { json: { id: lead.id, website: lead.website, tech } };

// Pull screenshot base64 + tech findings, build the Gemini request body.
const tech = $('Tech Analysis').item.json.tech || {};
const id = $('Prep').item.json.id;
const website = $('Prep').item.json.website;

let screenshotBase64 = '';
try {
  const bin = $input.item.binary;
  if (bin && bin.data && bin.data.data) screenshotBase64 = bin.data.data;
} catch (e) {}

const prompt = `You are auditing a small business website for a cold-outreach agency. `
  + `Automated technical checks (JSON): ${JSON.stringify(tech)}. `
  + (screenshotBase64
      ? `A screenshot of the homepage is attached. `
      : `No screenshot available, judge from the technical findings only. `)
  + `Identify only the MAJOR issues, things a business owner would care about and that hurt conversions or credibility. `
  + `Return STRICT JSON, no markdown, exactly this shape: `
  + `{"score": <integer 0-100, lower means worse>, "summary": "<one sentence>", `
  + `"issues": [{"issue":"...","severity":"high|medium|low","evidence":"..."}], `
  + `"top_issue": "<the single strongest, most specific, pitchable issue in one sentence>"}`;

const parts = [{ text: prompt }];
if (screenshotBase64) parts.push({ inline_data: { mime_type: 'image/png', data: screenshotBase64 } });

const geminiBody = {
  contents: [{ parts }],
  generationConfig: { temperature: 0.2, response_mime_type: 'application/json' }
};

return { json: { id, website, tech, hasScreenshot: !!screenshotBase64, geminiBody } };

// Parse Gemini, fold in hard technical red flags, build the update body.
const ctx = $('Build Gemini Input').item.json;
const tech = ctx.tech || {};

let parsed = null, ok = false, errMsg = null;
try {
  const resp = $input.item.json;
  const txt = resp && resp.candidates && resp.candidates[0]
    && resp.candidates[0].content && resp.candidates[0].content.parts
    && resp.candidates[0].content.parts[0] && resp.candidates[0].content.parts[0].text;
  if (txt) { parsed = JSON.parse(txt); ok = true; }
  else { errMsg = 'No text returned by Gemini'; }
} catch (e) { errMsg = String(e); }

const techFlags = [];
if (tech.reachable === false) techFlags.push({issue:'Website is unreachable or returning an error', severity:'high', evidence:'HTTP status ' + tech.statusCode});
if (tech.isHttps === false) techFlags.push({issue:'No HTTPS / insecure site', severity:'high', evidence:'not served over https'});
if (tech.hasViewport === false) techFlags.push({issue:'Not mobile friendly (no viewport meta tag)', severity:'high', evidence:'missing viewport meta'});
if (tech.hasContactMethod === false) techFlags.push({issue:'No clear way to contact the business', severity:'high', evidence:'no phone, email, form or booking link found'});
if (!tech.title) techFlags.push({issue:'Missing page title (SEO)', severity:'medium', evidence:'no <title> tag'});
if (!tech.metaDescription) techFlags.push({issue:'Missing meta description (SEO)', severity:'low', evidence:'no meta description'});
if (tech.hasChatWidget === false) techFlags.push({issue:'No live chat or AI assistant to capture visitors', severity:'medium', evidence:'no chat widget detected'});
if (tech.staleCopyright === true) techFlags.push({issue:'Outdated / stale site', severity:'low', evidence:'copyright year ' + tech.copyrightYear});

const aiIssues = ok && Array.isArray(parsed.issues) ? parsed.issues : [];
const allIssues = [...techFlags, ...aiIssues];

const score = (ok && typeof parsed.score === 'number')
  ? parsed.score
  : (allIssues.some(i => i.severity === 'high') ? 30 : 60);
const summary = ok ? (parsed.summary || '') : ('Analysis failed: ' + (errMsg || 'unknown'));
const topIssue = ok ? (parsed.top_issue || '') : ((techFlags[0] && techFlags[0].issue) || '');
const auditStatus = (ok || techFlags.length > 0) ? 'done' : 'failed';

return { json: {
  id: ctx.id,
  updateBody: {
    audit_status: auditStatus,
    audit_score: score,
    audit_issues: allIssues,
    audit_summary: summary,
    top_issue: topIssue,
    screenshot_url: null,
    audited_at: new Date().toISOString()
  }
}};
